\begin{align*}
\frac{a}{\sin 150} &= \frac{5}{\cos 30},\\
\frac{a}{\frac{1}{2}} &= \frac{5}{\frac{\sqrt{3}}{2}},\\
a &= \frac{5}{\sqrt{3}}\cdot \frac{1}{3},\\
a &= \frac{10}{\sqrt{3}}.
